userDefinedLinkHintCss:
/*
Vampiric theme for vimium
Based on: Dracula theme for Vimium
by Trollwut (trollwut@trollwut.org) with changed colours
*/

:root {
  --darkblood: #1a0000;
  --witchfire: #c9b45c;
  --palemoon: #d8d8e8;
  --crimson: #750b12;
  --phantommist: #9ca8c0;
  --poison: #7a8a4d;
  --ember: #d98a6d;
   --nightshade: #4f556e
}

/* Link hint boxes */
div > .vimiumHintMarker {
  background: var(--darkblood);
  font-size: 12px;
  border: 0.25em solid var(--witchfire);
  border-radius: 0.34em;
  box-shadow: 0em 0.1em 0.6em 0.1em rgba(0, 0, 0, 0.4);
}

/* Link hint text */
div > .vimiumHintMarker span {
  color: var(--palemoon);
  font-size: inherit;
  text-shadow: none;
}

/* Link hint matching characters */
div > .vimiumHintMarker > .matchingCharacter {
  color: var(--crimson);
}

/* HUD ("heads-up display") bar */
div.vimiumHUD {
  background: var(--darkblood);
  border: 1px solid var(--nightshade);
}

div.vimiumHUD .vimiumHUDSearchArea {
  background: var(--darkblood);
}

div.vimiumHUD .hud-find {
  background: var(--darkblood);
  border: none;
  color: var(--palemoon);
}

div.vimiumHUD span#hud-find-input {
  color: var(--palemoon);
}

div.vimiumHUD span#hud-match-count {
  color: var(--crimson);
}

div.vimiumHUD .vimiumHUDSearchAreaInner {
  color: var(--nightshade);
}

#vomnibar {
  background-color: var(--darkblood);
}

#vomnibar input {
  color: var(--palemoon);
  font: -moz-window;
  font-size: 20px;
  height: 34px;
  margin-bottom: 0;
  padding: 4px;
  background-color: var(--darkblood);
  border-radius: 3px;
  border: 1px solid var(--crimson);
  box-shadow: var(--phantommist) 0px 0px 1px;
  width: 100%;
  outline: none;
  box-sizing: border-box;
}

#vomnibar .vomnibarSearchArea {
  display: block;
  padding: 1px;
  background-color: var(--nightshade);
  border-radius: 4px 4px 0 0;
  border-bottom: 0px solid var(--phantommist);
}

#vomnibar ul {
  background-color: var(--darkblood);
  border-radius: 0 0 4px 4px;
  list-style: none;
  padding-top: 0;
  padding-bottom: 0;
  margin-block-start: 2px;
  margin-block-end: 0px;
}

#vomnibar li {
  border-bottom: 1px solid var(--crimson);
  line-height: 1.1em;
  padding: 7px 10px;
  font-size: 16px;
  color: var(--palemoon);
  position: relative;
  display: list-item;
  margin: auto;
}

#vomnibar li .vomnibarBottomHalf {
  font-size: 15px;
  margin-top: 3px;
  padding: 2px 0;
}

#vomnibar li .vomnibarSource {
  color: var(--phantommist);
  margin-right: 4px;
}

#vomnibar li .vomnibarRelevancy {
  position: absolute;
  right: 0;
  top: 0;
  padding: 5px;
  background-color: var(--darkblood);
  color: var(--palemoon);
  font-family: monospace;
  width: 100px;
  overflow: hidden;
}

#vomnibar li .vomnibarUrl {
  white-space: nowrap;
  color: var(--poison);
}

#vomnibar li .vomnibarMatch {
  font-weight: bold;
  color: var(--ember);
}

#vomnibar li em, #vomnibar li .vomnibarTitle {
  color: var(--palemoon);
  margin-left: 4px;
  font-weight: normal;
}

#vomnibar li em {
  font-style: italic;
}

#vomnibar li em .vomnibarMatch,
#vomnibar li .vomnibarTitle .vomnibarMatch {
  color: var(--witchfire);
}

#vomnibar li.vomnibarSelected {
  background-color: var(--crimson);
  font-weight: normal;
}

#vomnibarInput::selection {
  background-color: var(--witchfire);
}
